import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const HomePage = () => {
  const [products, setProducts] = useState([]);
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  // Danh mục giả lập (dùng Emoji thay cho icon ảnh để nhẹ web)
  const categories = [
    { id: 1, name: 'Bất động sản', icon: '🏠' },
    { id: 2, name: 'Xe cộ', icon: '🛵' },
    { id: 3, name: 'Đồ điện tử', icon: '📱' },
    { id: 4, name: 'Việc làm', icon: '💼' },
    { id: 5, name: 'Thú cưng', icon: '🐶' },
    { id: 6, name: 'Tủ lạnh', icon: '❄️' },
  ];

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const { data } = await axios.get('http://localhost:5000/api/products');
        setProducts(data);
      } catch (error) { console.error(error); }
    };
    fetchProducts();

    const userInfo = localStorage.getItem('userInfo');
    if (userInfo) setUser(JSON.parse(userInfo));
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('userInfo');
    setUser(null);
    navigate('/login');
  };

  // --- HÀM QUAN TRỌNG: CHỐT CHẶN BẢO VỆ ---
  // Bất kỳ hành động nào cần đăng nhập sẽ gọi hàm này
  const handleAuthRequired = (actionName) => {
    if (user) {
      // Nếu đã đăng nhập thì cho phép làm tiếp (Ở đây mình chỉ alert demo)
      alert(`Bạn đang xem ${actionName} (Đã xác thực)`);
      // Sau này sẽ là: navigate('/product/123')
    } else {
      // Nếu chưa đăng nhập
      const confirmLogin = window.confirm(`Bạn cần đăng nhập để xem ${actionName}. Đi đến trang đăng nhập ngay?`);
      if (confirmLogin) {
        navigate('/login');
      }
    }
  };

  return (
    <div style={{ paddingBottom: '80px', backgroundColor: '#F4F4F4', minHeight: '100vh' }}>
      
      {/* 1. HEADER MÀU VÀNG */}
      <header className="bg-chotot py-3 sticky-top shadow-sm">
        <div className="container">
          <div className="d-flex justify-content-between align-items-center mb-2">
            <h2 className="fw-bold text-dark m-0" style={{cursor: 'pointer'}}>HaiHand</h2>
            {user ? (
               <div className="d-flex align-items-center gap-2">
                 <span className="fw-bold">Hi, {user.name}</span>
                 <button onClick={handleLogout} className="btn btn-sm btn-dark text-warning">Thoát</button>
               </div>
            ) : (
               <span className="fw-bold" onClick={() => navigate('/login')} style={{cursor:'pointer'}}>Đăng nhập</span>
            )}
          </div>

          {/* Ô TÌM KIẾM */}
          <div className="input-group">
            <input 
              type="text" 
              className="form-control border-0" 
              placeholder="Tìm kiếm trên HaiHand..." 
              onClick={() => handleAuthRequired('Tìm kiếm')} // <--- Chặn tìm kiếm
              readOnly={!user} // Nếu chưa đăng nhập thì không cho gõ, bấm vào là chặn luôn
            />
            <button className="btn btn-dark text-warning" onClick={() => handleAuthRequired('Tìm kiếm')}>
              🔍
            </button>
          </div>
        </div>
      </header>

      <div className="container mt-3">
        
        {/* 2. DANH MỤC (CATEGORIES) */}
        <div className="bg-white p-3 rounded shadow-sm mb-3">
            <h6 className="fw-bold mb-3">Khám phá danh mục</h6>
            <div className="d-flex justify-content-between text-center overflow-auto">
                {categories.map(cat => (
                    <div key={cat.id} className="category-item px-2" onClick={() => handleAuthRequired(`Danh mục ${cat.name}`)}>
                        <div className="category-icon">{cat.icon}</div>
                        <small style={{fontSize: '12px'}}>{cat.name}</small>
                    </div>
                ))}
            </div>
        </div>

        {/* 3. DANH SÁCH SẢN PHẨM (GRID) */}
        <div className="bg-white p-3 rounded shadow-sm">
          <h6 className="fw-bold mb-3">Tin đăng mới dành cho bạn</h6>
          <div className="row">
            {products.map((product) => (
              <div className="col-6 col-md-3 mb-3" key={product._id} onClick={() => handleAuthRequired('Chi tiết sản phẩm')}>
                <div className="card h-100 border-0 shadow-sm" style={{cursor: 'pointer'}}>
                  <img 
                    src={product.image} 
                    className="card-img-top rounded" 
                    alt={product.name} 
                    style={{height: '150px', objectFit: 'cover'}}
                  />
                  <div className="card-body p-2">
                    <h6 className="card-title text-truncate mb-1">{product.name}</h6>
                    <p className="card-text text-danger fw-bold mb-0">
                      {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(product.price)}
                    </p>
                    <small className="text-muted" style={{fontSize: '10px'}}>Vừa đăng xong</small>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

      </div>

      {/* 4. BANNER ĐỀ XUẤT ĐĂNG NHẬP (Giống ảnh bạn gửi) */}
      {!user && (
        <div className="sticky-banner d-flex justify-content-between align-items-center animate__animated animate__slideInUp">
            <div>
                <p className="mb-0 fw-bold">Đăng nhập ngay để không bỏ lỡ deal hời!</p>
                <small className="text-muted">Hàng ngàn món hời đang chờ bạn.</small>
            </div>
            <button onClick={() => navigate('/login')} className="btn btn-chotot px-4">
                Đăng nhập
            </button>
        </div>
      )}

    </div>
  );
};

export default HomePage;
